import React, { useState, useMemo } from "react";
import { useData } from "../lib/DataContext";
import { Plus, X, Search, AlertTriangle, CheckCircle, Tool } from "lucide-react";

const STATUS_OPTIONS = ["Activo", "En Reparación", "Inactivo"];
const TYPE_OPTIONS   = ["Excavadora", "Grúa", "Compactadora", "Montacargas", "Retroexcavadora", "Camión", "Generador", "Otro"];

function statusBadge(s) {
  const map = { "Activo": "badge-success", "En Reparación": "badge-warn", "Inactivo": "badge-danger" };
  return <span className={`badge ${map[s] || "badge-neutral"}`}>{s}</span>;
}

function EquipmentModal({ onClose, onSave }) {
  const [form, setForm] = useState({
    name: "", type: TYPE_OPTIONS[0], serial: "", status: "Activo",
    lastService: "", nextService: "", notes: ""
  });
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));
  const handleSave = () => {
    if (!form.name || !form.serial) { alert("Nombre y serie son requeridos."); return; }
    onSave(form);
  };

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <div className="modal-header">
          <span className="modal-title">Agregar Equipo</span>
          <button className="btn btn-icon btn-ghost" onClick={onClose}><X size={18} /></button>
        </div>
        <div className="modal-body">
          <div className="form-grid">
            <div className="form-group" style={{ gridColumn: "1 / -1" }}>
              <label className="form-label">Nombre del equipo *</label>
              <input className="form-input" value={form.name} onChange={e => set("name", e.target.value)} placeholder="Ej: Excavadora CAT 320" />
            </div>
            <div className="form-group">
              <label className="form-label">Tipo</label>
              <select className="form-input" value={form.type} onChange={e => set("type", e.target.value)}>
                {TYPE_OPTIONS.map(t => <option key={t}>{t}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Número de serie *</label>
              <input className="form-input" value={form.serial} onChange={e => set("serial", e.target.value)} placeholder="SN-000000" />
            </div>
            <div className="form-group">
              <label className="form-label">Estado</label>
              <select className="form-input" value={form.status} onChange={e => set("status", e.target.value)}>
                {STATUS_OPTIONS.map(s => <option key={s}>{s}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Último servicio</label>
              <input className="form-input" type="date" value={form.lastService} onChange={e => set("lastService", e.target.value)} />
            </div>
            <div className="form-group" style={{ gridColumn: "1 / -1" }}>
              <label className="form-label">Próximo servicio</label>
              <input className="form-input" type="date" value={form.nextService} onChange={e => set("nextService", e.target.value)} />
            </div>
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn btn-ghost" onClick={onClose}>Cancelar</button>
          <button className="btn btn-primary" onClick={handleSave}>Guardar Equipo</button>
        </div>
      </div>
    </div>
  );
}

export default function Equipment() {
  const { equipment, workOrders, addEquipment, loading } = useData();
  const [showModal, setShowModal] = useState(false);
  const [search, setSearch] = useState("");
  const [filterStatus, setFilterStatus] = useState("Todos");

  const filtered = useMemo(() => {
    return equipment.filter(eq => {
      const q = search.toLowerCase();
      const matchQ = !q || eq.name?.toLowerCase().includes(q) || eq.serial?.toLowerCase().includes(q) || eq.type?.toLowerCase().includes(q);
      const matchS = filterStatus === "Todos" || eq.status === filterStatus;
      return matchQ && matchS;
    });
  }, [equipment, search, filterStatus]);

  const getOpenOrders = (eqId) =>
    workOrders.filter(w => w.equipmentId === eqId && w.status !== "Completado" && w.status !== "Cancelado").length;

  const handleSave = async (form) => {
    await addEquipment(form);
    setShowModal(false);
  };

  // Summary counts
  const counts = useMemo(() => ({
    active:   equipment.filter(e => e.status === "Activo").length,
    repair:   equipment.filter(e => e.status === "En Reparación").length,
    inactive: equipment.filter(e => e.status === "Inactivo").length,
  }), [equipment]);

  if (loading) return <div className="empty-state"><p>Cargando…</p></div>;

  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">Gestión de Equipos</h1>
          <p className="page-subtitle">{equipment.length} equipos registrados</p>
        </div>
        <button className="btn btn-primary" onClick={() => setShowModal(true)}>
          <Plus size={16} /> Agregar Equipo
        </button>
      </div>

      {/* Summary */}
      <div className="grid-3 mb-24">
        <div className="stat-card" style={{ "--accent-line": "var(--success)" }}>
          <span className="stat-label">Activos</span>
          <span className="stat-value">{counts.active}</span>
          <span className="stat-sub">en operación</span>
        </div>
        <div className="stat-card" style={{ "--accent-line": "var(--warn)" }}>
          <span className="stat-label">En Reparación</span>
          <span className="stat-value">{counts.repair}</span>
          <span className="stat-sub">fuera de servicio</span>
        </div>
        <div className="stat-card" style={{ "--accent-line": "var(--danger)" }}>
          <span className="stat-label">Inactivos</span>
          <span className="stat-value">{counts.inactive}</span>
          <span className="stat-sub">sin uso</span>
        </div>
      </div>

      {/* Filters */}
      <div style={{ display: "flex", gap: 12, marginBottom: 20, flexWrap: "wrap" }}>
        <div style={{ position: "relative", flex: 1, minWidth: 200 }}>
          <Search size={14} style={{ position: "absolute", left: 10, top: "50%", transform: "translateY(-50%)", color: "var(--text3)" }} />
          <input className="form-input" style={{ paddingLeft: 32 }} placeholder="Buscar equipos…" value={search} onChange={e => setSearch(e.target.value)} />
        </div>
        <select className="form-input" style={{ width: "auto" }} value={filterStatus} onChange={e => setFilterStatus(e.target.value)}>
          <option value="Todos">Todos los estados</option>
          {STATUS_OPTIONS.map(s => <option key={s}>{s}</option>)}
        </select>
      </div>

      {/* Equipment cards grid */}
      <div className="grid-3">
        {filtered.map(eq => {
          const openOrders = getOpenOrders(eq.id);
          return (
            <div key={eq.id} className="card" style={{
              borderLeft: `3px solid ${eq.status === "Activo" ? "var(--success)" : eq.status === "En Reparación" ? "var(--warn)" : "var(--danger)"}`,
              padding: "18px"
            }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                <div>
                  <div style={{ fontWeight: 600, fontSize: 15, marginBottom: 2 }}>{eq.name}</div>
                  <div style={{ fontSize: 11, fontFamily: "var(--font-mono)", color: "var(--text3)" }}>{eq.type}</div>
                </div>
                {statusBadge(eq.status)}
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: 6, fontSize: 12 }}>
                <div style={{ display: "flex", justifyContent: "space-between", color: "var(--text2)" }}>
                  <span style={{ fontFamily: "var(--font-mono)", color: "var(--text3)" }}>Serie</span>
                  <span style={{ fontFamily: "var(--font-mono)" }}>{eq.serial}</span>
                </div>
                {eq.lastService && (
                  <div style={{ display: "flex", justifyContent: "space-between", color: "var(--text2)" }}>
                    <span style={{ color: "var(--text3)" }}>Último servicio</span>
                    <span>{eq.lastService}</span>
                  </div>
                )}
                {eq.nextService && (
                  <div style={{ display: "flex", justifyContent: "space-between", color: "var(--text2)" }}>
                    <span style={{ color: "var(--text3)" }}>Próximo servicio</span>
                    <span style={{ color: new Date(eq.nextService) < new Date() ? "var(--danger)" : "var(--text2)" }}>
                      {new Date(eq.nextService) < new Date() ? "⚠ " : ""}{eq.nextService}
                    </span>
                  </div>
                )}
              </div>
              {openOrders > 0 && (
                <div style={{ marginTop: 12, padding: "6px 10px", background: "rgba(245,166,35,0.08)", borderRadius: "var(--radius)", fontSize: 12, color: "var(--warn)", display: "flex", alignItems: "center", gap: 6 }}>
                  <AlertTriangle size={12} />
                  {openOrders} orden{openOrders > 1 ? "es" : ""} abierta{openOrders > 1 ? "s" : ""}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {filtered.length === 0 && (
        <div className="empty-state">
          <p>No hay equipos que coincidan</p>
        </div>
      )}

      {showModal && <EquipmentModal onClose={() => setShowModal(false)} onSave={handleSave} />}
    </div>
  );
}
